import threading

class BreachRegistry:
    """In-memory store for active breaches; use a durable store in production."""

    def __init__(self):
        self._active: dict[str, BreachEvent] = {}  # key = contract_id + term_type
        self._lock = threading.Lock()

    def _key(self, event: BreachEvent) -> str:
        return f"{event.contract_id}::{event.term_type}"

    def open(self, event: BreachEvent) -> bool:
        """Register a new breach. Returns True if this is a new (not duplicate) breach."""
        key = self._key(event)
        with self._lock:
            if key in self._active:
                return False          # already tracking this breach dimension
            self._active[key] = event
            return True

    def close(self, contract_id: str, term_type: str) -> Optional[BreachEvent]:
        """Mark a breach resolved after the monitor clears. Returns the closed event."""
        key = f"{contract_id}::{term_type}"
        with self._lock:
            return self._active.pop(key, None)

    def active_breaches(self, contract_id: str) -> list[BreachEvent]:
        with self._lock:
            return [e for k, e in self._active.items() if k.startswith(contract_id)]

    def any_active(self, contract_id: str) -> bool:
        return len(self.active_breaches(contract_id)) > 0

class ContractBreachHandler:
    """
    Coordinates detection → notification → remediation → verification.
    Instantiate once per contract and call handle() for each monitor result.
    """

    REMEDIATION_MAP: dict[str, RemediationAction] = {
        "freshness":          RemediationAction.RE_DELIVER,
        "completeness":       RemediationAction.RE_DELIVER,
        "null_rate":          RemediationAction.FIELD_PATCH,
        "duplicate_rate":     RemediationAction.BACKFILL,
        "ingestion_latency":  RemediationAction.ESCALATE,
    }

    def __init__(self, contract_id: str, registry: BreachRegistry):
        self.contract_id = contract_id
        self.registry = registry

    def handle(self, monitor_result, batch_id: Optional[str] = None) -> None:
        if monitor_result.healthy:
            # Try to close any breaches that are now resolved
            self._close_resolved(monitor_result)
            return

        for violation in monitor_result.violations:
            event = BreachEvent.from_violation(violation, self.contract_id, batch_id)
            is_new = self.registry.open(event)
            if is_new:
                self._notify(event)
                self._remediate(event)

    def _notify(self, event: BreachEvent) -> None:
        """Dispatch within the contractual breach_notification SLA (≤ 15 min)."""
        if event.severity == BreachSeverity.P1:
            _page_oncall(event)
        elif event.severity == BreachSeverity.P2:
            _slack_alert(event)
        else:
            _log_p3(event)

    def _remediate(self, event: BreachEvent) -> None:
        action = self.REMEDIATION_MAP.get(event.term_type, RemediationAction.ESCALATE)
        print(f"[REMEDIATE] {event.contract_id} | {event.term_type} | "
              f"{action.value} | severity={event.severity.value}")
        if action == RemediationAction.RE_DELIVER:
            _trigger_re_delivery(event.contract_id, event.batch_id)
        elif action == RemediationAction.BACKFILL:
            _trigger_backfill(event.contract_id, event.batch_id)
        elif action == RemediationAction.FIELD_PATCH:
            _trigger_field_patch(event.contract_id, event.batch_id, event.term_type)
        elif action == RemediationAction.ESCALATE:
            _escalate_to_oncall(event)

    def _close_resolved(self, monitor_result) -> None:
        """On a clean monitor pass, close any breaches for this contract."""
        currently_active = self.registry.active_breaches(self.contract_id)
        still_violating = {v.term.term_type.value for v in monitor_result.violations}
        for event in currently_active:
            if event.term_type not in still_violating:
                self.registry.close(self.contract_id, event.term_type)
                print(f"[RESOLVED] {self.contract_id} | {event.term_type} "
                      f"— breach closed after {event.elapsed_seconds():.0f}s")

# --- Remediation action stubs (replace with real integrations) ---

def _trigger_re_delivery(contract_id: str, batch_id: Optional[str]) -> None:
    """Signal the producer pipeline to re-send the failed batch."""
    # In practice: POST to the producer's replay API or put a message on a queue.
    print(f"[RE-DELIVER] {contract_id} batch={batch_id}")

def _trigger_backfill(contract_id: str, batch_id: Optional[str]) -> None:
    """Schedule a backfill job to reprocess a time window without duplicates."""
    print(f"[BACKFILL] {contract_id} batch={batch_id}")

def _trigger_field_patch(contract_id: str, batch_id: Optional[str], term: str) -> None:
    """Apply targeted fixes to null or invalid fields for the affected batch."""
    print(f"[PATCH] {contract_id} batch={batch_id} field={term}")

def _escalate_to_oncall(event: BreachEvent) -> None:
    """Send PagerDuty/OpsGenie alert when automated remediation is not sufficient."""
    print(f"[ESCALATE] {event.contract_id} | {event.term_type} | {event.severity.value}")

def _page_oncall(event: BreachEvent) -> None:
    print(f"[P1-PAGE] {event.contract_id} | {event.term_type} actual={event.actual:.3f}")

def _slack_alert(event: BreachEvent) -> None:
    print(f"[P2-SLACK] {event.contract_id} | {event.term_type} actual={event.actual:.3f}")

def _log_p3(event: BreachEvent) -> None:
    print(f"[P3-LOG] {event.contract_id} | {event.term_type} actual={event.actual:.3f}")

from enum import Enum

class ConsumerMode(Enum):
    NORMAL   = "normal"    # serve live retrieval results
    FALLBACK = "fallback"  # serve cached results with staleness warning
    SUPPRESSED = "suppressed"  # hide AI answers entirely (P1 with no cache)

class FallbackRAGRetriever:
    """
    Consumer-side retriever that degrades gracefully when a breach is active.
    """

    def __init__(self, live_retriever, cache_retriever, breach_registry: BreachRegistry, contract_id: str):
        self.live = live_retriever
        self.cache = cache_retriever
        self.registry = breach_registry
        self.contract_id = contract_id

    def _current_mode(self) -> ConsumerMode:
        breaches = self.registry.active_breaches(self.contract_id)
        if not breaches:
            return ConsumerMode.NORMAL
        p1 = any(b.severity == BreachSeverity.P1 for b in breaches)
        return ConsumerMode.SUPPRESSED if p1 else ConsumerMode.FALLBACK

    def retrieve(self, query: str, top_k: int = 5) -> dict:
        mode = self._current_mode()
        if mode == ConsumerMode.NORMAL:
            return {"results": self.live.retrieve(query, top_k), "mode": "live"}
        elif mode == ConsumerMode.FALLBACK:
            cached = self.cache.retrieve(query, top_k)
            return {
                "results": cached,
                "mode": "fallback",
                "warning": "Results may be up to 48 hours old due to a data quality issue.",
            }
        else:  # SUPPRESSED
            return {
                "results": [],
                "mode": "suppressed",
                "error": "AI answers temporarily unavailable. Please contact support.",
            }
